"""CSS token output plugin — generates pui-tokens-{hub}.css."""

from __future__ import annotations

from pathlib import Path

from hub_identity.core.plugins import GeneratedFile
from hub_identity.core.schema import HubDNA


CSS_TEMPLATE = """\
/* pui-tokens-{hub}.css — DO NOT EDIT (generated by iil-hub-identity)
 * Hub: {hub} | Display: {display_name}
 * Personality: {personality}
 * @pui-meta: generated
 */

@import url("{font_source}/css?family={font_display}:wght@400;500;600;700&family={font_body}:wght@400;500;600&family={font_mono}:wght@400;500&display=swap");

:root {{
  /* ── Palette ──────────────────────────── */
  --pui-primary: {primary};
  --pui-primary-foreground: {primary_fg};
  --pui-secondary: {secondary};
  --pui-secondary-foreground: {secondary_fg};
  --pui-accent: {accent};
  --pui-accent-foreground: {accent_fg};
  --pui-background: {background};
  --pui-foreground: {foreground};
  --pui-muted: {muted};
  --pui-muted-foreground: {muted_fg};
  --pui-destructive: {destructive};
  --pui-border: {border};
  --pui-ring: {ring};

  /* ── Typography ───────────────────────── */
  --pui-font-display: "{font_display}", sans-serif;
  --pui-font-body: "{font_body}", sans-serif;
  --pui-font-mono: "{font_mono}", monospace;
  --pui-font-size-base: {base_size};
  --pui-font-scale: {scale_ratio};

  /* ── Layout ───────────────────────────── */
  --pui-radius: {radius}px;
  --pui-spacing: {spacing}px;
  --pui-container-max: {container_max};

  /* ── Motion ───────────────────────────── */
  --pui-duration-fast: {dur_fast};
  --pui-duration-normal: {dur_normal};
  --pui-duration-slow: {dur_slow};
  --pui-easing: {easing};

  /* ── Shadows ──────────────────────────── */
  --pui-shadow-sm: {shadow_sm};
  --pui-shadow-md: {shadow_md};
  --pui-shadow-lg: {shadow_lg};
  --pui-shadow-accent: {shadow_accent};
}}
"""


class CSSOutput:
    """Generate hub-specific CSS token files."""

    name = "css"
    format = "css"

    def generate(
        self, dna: HubDNA, output_dir: Path,
    ) -> list[GeneratedFile]:
        v = dna.visual
        content = CSS_TEMPLATE.format(
            hub=dna.hub,
            display_name=dna.display_name,
            personality=dna.personality,
            font_source=v.typography.font_source,
            font_display=v.typography.display,
            font_body=v.typography.body,
            font_mono=v.typography.mono,
            primary=v.palette.primary,
            primary_fg=v.palette.primary_foreground,
            secondary=v.palette.secondary,
            secondary_fg=v.palette.secondary_foreground,
            accent=v.palette.accent,
            accent_fg=v.palette.accent_foreground,
            background=v.palette.background,
            foreground=v.palette.foreground,
            muted=v.palette.muted,
            muted_fg=v.palette.muted_foreground,
            destructive=v.palette.destructive,
            border=v.palette.border,
            ring=v.palette.ring,
            base_size=v.typography.base_size,
            scale_ratio=v.typography.scale_ratio,
            radius=v.layout.border_radius,
            spacing=v.layout.spacing_unit,
            container_max=v.layout.container_max_width,
            dur_fast=v.motion.duration_fast,
            dur_normal=v.motion.duration_normal,
            dur_slow=v.motion.duration_slow,
            easing=v.motion.easing,
            shadow_sm=v.shadow.sm,
            shadow_md=v.shadow.md,
            shadow_lg=v.shadow.lg,
            shadow_accent=v.shadow.accent or "none",
        )

        path = output_dir / dna.get_css_filename()
        return [GeneratedFile(
            path=path, content=content, format="css",
        )]
